; CHECK-NEXT:    [[EXP:%.*]] = call ninf float @llvm.exp.f32(float [[X]])
; CHECK-NEXT:    ret float [[EXP]]
  %exp = call float @llvm.exp.f32(float %x)
  ret float %exp
}

